import { isEqual } from 'lodash-es';

import type { FilterSegment } from '@dynatrace-sdk/client-query';

/** @internal */
function getSortedVariables(variables: FilterSegment['variables']) {
  return variables?.map((segment) => {
    const sortedValues = segment.values.toSorted((firstValue, secondValue) =>
      firstValue.localeCompare(secondValue),
    );

    return {
      ...segment,
      values: sortedValues,
    };
  });
}

/** @internal */
export function isSelectedPreset(
  selectedSegments: FilterSegment[],
  presetSegments: FilterSegment[],
) {
  if (
    selectedSegments.length === 0 ||
    selectedSegments.length !== presetSegments.length
  ) {
    return false;
  }

  // Checks if every selected segment can be found in the segments preset
  return selectedSegments.every((selectedSegment) => {
    return presetSegments.some((presetSegment) => {
      const sameID = presetSegment.id === selectedSegment.id;
      const selectedHasVariables = selectedSegment.variables !== undefined;
      const presetHasVariables = presetSegment.variables !== undefined;

      if (!sameID || (!selectedHasVariables && !presetHasVariables)) {
        return sameID;
      }

      // If one of the segments has variables and the other doesn't, they are not equal
      if (
        (selectedHasVariables && !presetHasVariables) ||
        (!selectedHasVariables && presetHasVariables)
      ) {
        return false;
      }

      const sortedSelectedVariables = getSortedVariables(
        selectedSegment.variables,
      );
      const sortedPresetVariables = getSortedVariables(presetSegment.variables);

      return isEqual(sortedPresetVariables, sortedSelectedVariables);
    });
  });
}
